import{_ as a,o as s,c as e,a2 as t}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"Wiki-links","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/wiki-links.md","filePath":"zh/guide/wiki-links.md","lastUpdated":1783734888000}'),n={name:"zh/guide/wiki-links.md"};function l(o,i,d,h,r,p){return s(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="wiki-links" tabindex="-1">Wiki-links <a class="header-anchor" href="#wiki-links" aria-label="Permalink to &quot;Wiki-links&quot;">​</a></h1><p>wiki-link 是写在内容里的引用 —— 就是你在维基和 Obsidian 里见过的 <code>[[...]]</code> 语法 —— 在 wikimem 中它永远指向<strong>一个条目（item）</strong>：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># preferences.md</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## likes-the-sea</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">喜欢海边，提到过想去海边玩。[[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">daily_life:beach-trip-plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># daily_life.md</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## beach-trip-plan</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">计划夏天去海边旅行，看日出。</span></span></code></pre></div><p><code>[[daily_life:beach-trip-plan]]</code> 是一个两段式地址：<strong>category</strong>（哪个文件 —— <code>daily_life.md</code>）+ <strong>条目名</strong>（文件里哪个 <code>##</code> 标题）。所以被链接的节点是 <em>条目</em>：一个有名字、自包含、几句话规模的记忆 —— <strong>不是词，也不是整个文件</strong>。</p><p>检索命中 <code>likes-the-sea</code> 时，会机械展开它的链接一跳，把整个 <code>beach-trip-plan</code> 条目一并注入 —— 不调 LLM、没有图数据库。 &quot;图&quot;就是文本本身，展开只是一次按名字的精确查找。</p><h2 id="已经有搜索了-为什么还要链接" tabindex="-1">已经有搜索了，为什么还要链接？ <a class="header-anchor" href="#已经有搜索了-为什么还要链接" aria-label="Permalink to &quot;已经有搜索了，为什么还要链接？&quot;">​</a></h2><ul><li><strong>搜索找到的是&quot;词面相似&quot;，链接记录的是&quot;含义相关&quot;。</strong> 咖啡偏好和早晨习惯 可能一个词都不重合 —— 关键词（往往连 embedding）都搭不上，但记忆写入时 留下的一条链接可以。</li><li><strong>全程同一个单元。</strong> 链接目标就是检索排序、token 预算裁剪所用的同一个单元： 条目。比 Obsidian 的&quot;文件级节点&quot;更细 —— 展开一条链接永远不会把整份文档 灌进 prompt。</li><li><strong>人和 LLM 都能读写。</strong> 抽取 LLM 在写入记忆的同一趟里顺手产出链接； 你可以在任何编辑器里增删改它；<code>git diff</code> 看得见。</li><li><strong>零基础设施、坏了不炸。</strong> 它取代的是图数据库（前代设计为此跑着 Neo4j）。 悬空链接 —— 目标被改名或删除 —— 会被容忍并报告，绝不崩溃。</li></ul><h2 id="链接是谁写的" tabindex="-1">链接是谁写的？ <a class="header-anchor" href="#链接是谁写的" aria-label="Permalink to &quot;链接是谁写的？&quot;">​</a></h2><p>会打两对方括号的都行：</p><ul><li><strong>抽取 LLM</strong>，在写入记忆的同一趟里。宿主把本轮检索刚浮现的条目名作为候选 链接目标传给它，模型负责把新事实连到旧条目上 —— 见<a href="/zh/guide/host-integration.html">宿主集成</a>。</li><li><strong>你自己</strong>，在任何编辑器里。链接就是内容里的纯文本；下次 <code>rebuild()</code> （或进程重启）自然生效。</li></ul><h2 id="解析规则" tabindex="-1">解析规则 <a class="header-anchor" href="#解析规则" aria-label="Permalink to &quot;解析规则&quot;">​</a></h2><p>链接解析刻意做得宽松，因为手改过的文件绝不能让读取崩溃：</p><ul><li>语法是 <code>[[category:name]]</code> —— category 取到<strong>第一个</strong>冒号为止； 两侧都不能含 <code>[</code>、<code>]</code>、换行或另一个冒号。</li><li>两侧的空白会被去掉；残缺或空的链接被解析器静默忽略（不是错误）。</li><li>条目名<strong>从源头上</strong>保持无冒号：<code>sanitize_item_name</code> 在写入时拒绝 <code>[[</code>、<code>]]</code>、<code>:</code>、<code>|</code>、<code>#</code>，这让每条链接都无歧义、可 grep。</li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> wikimem </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> parse_wiki_links</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">parse_wiki_links(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;… [[daily_life:beach-trip-plan]] 和 [[坏掉的链接 …&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># [WikiLink(category=&#39;daily_life&#39;, name=&#39;beach-trip-plan&#39;)]</span></span></code></pre></div><h2 id="悬空链接" tabindex="-1">悬空链接 <a class="header-anchor" href="#悬空链接" aria-label="Permalink to &quot;悬空链接&quot;">​</a></h2><p>文件是用户可编辑的，链接目标随时可能被改名或删除。wikimem 把这当作日常， 而不是数据损坏：</p><ul><li>展开时跳过缺失的目标，继续处理其余链接。</li><li>未解析的地址记录在 <a href="/zh/reference/api.html#retrievalresult"><code>RetrievalResult.unresolved_links</code></a>， 宿主（或未来的 <code>wikimem graph</code> CLI）可以拿它提示修复。</li></ul><h2 id="边界-一跳-是刻意的" tabindex="-1">边界：一跳，是刻意的 <a class="header-anchor" href="#边界-一跳-是刻意的" aria-label="Permalink to &quot;边界：一跳，是刻意的&quot;">​</a></h2><p>展开只做恰好一跳 —— 命中拉进它直接链接的目标，目标<strong>不再</strong>拉它自己的链接； 多跳链条会随着对话逐轮触达、逐跳浮现。一跳让注入的上下文与命中数成正比、 token 成本可预期、行为可解释（&quot;这个条目在这里，因为那个命中链到了它&quot;）。 token 预算的<a href="/zh/guide/retrieval.html#_4-token-预算">前缀裁剪语义</a>出于同样的考虑。</p>`,19)])])}const g=a(n,[["render",l]]);export{c as __pageData,g as default};
